    public static int getTotalCount() {
        return ENTRIES.size();
    }

    public static ArtEntry getById(String id) {
        for (ArtEntry entry : ENTRIES) {
            if (entry.id().equals(id)) return entry;
        }
        return null;
    }

    public static boolean contains(String id) {
        return getById(id) != null;
    }

    public static String getDisplayString(ArtEntry entry) {
        return entry.title() + " by " + entry.artist() + " (" + entry.year() + ")";
    }

    public record ArtEntry(String id, String title, String artist, int year, String description) {
    }
